            aOrbiterC = (aWandererJ + RotL64(aCross, 53U)) + 0x3A29CF46D7999F14ULL;
            aOrbiterK = (((aWandererA + RotL64(aIngress, 11U)) + RotL64(aCarry, 47U)) + 0xE2A0BF7C743F59E2ULL) + aPhaseEOrbiterAssignSaltE[(((31U - aIndex) + 20U)) & S_SALT1];
