            aOrbiterJ = RotL64((aOrbiterJ * 0x181C6C1770F7BDCDULL), 47U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterF) + 0x37E5AB7386FBEA79ULL) + aPhaseEOrbiterUpdateSaltC[(((31U - aIndex) + 21U)) & S_SALT1];
