            aOrbiterA = ((aOrbiterA + aOrbiterG) + 0x1A78DBE11817E651ULL) + aPhaseEOrbiterUpdateSaltD[((aIndex + 8U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterA) ^ 0x6DF2D0AA0BB883C0ULL;
